using UnityEngine;
using UnityEngine.Events;

/// <summary>Material de um objecto destrutível (fichas do GDD).</summary>
public enum BreakableMaterial
{
    /// <summary>Madeira (troncos/barreiras) — Castor "rói madeira" (canBreakWood).</summary>
    Madeira,

    /// <summary>Pedra/objecto grande — Elefante/Urso Polar (canBreakBig).</summary>
    Grande,

    /// <summary>Gelo frágil — Urso Polar (canBreakIce).</summary>
    Gelo,

    /// <summary>Barreira rachada — Elefante "quebra barreiras rachadas" (canBreakBig).</summary>
    Rachada,

    /// <summary>Terra/rocha macia escavável (túneis) — Texugo/Wombat (canTunnel, P8). Abre por contacto contínuo ("escavar" — ver digDuration) ou por uma pancada de quem tiver canTunnel.</summary>
    Terra
}

/// <summary>
/// Objecto destrutível (P6): pedras, troncos, barreiras de madeira, gelo
/// frágil, paredes rachadas, terra escavável. Pode ser quebrado por:
///
/// - Ataques do player cuja forma tem a flag certa (TryBreakByForm —
///   canBreakWood/Big/Ice/Tunnel, chamado por PlayerAttack/HeavyStrikeAbility);
/// - Projécteis de inimigos com "canDestroyObjects" (IProjectileDestructible —
///   o ProjectileController já verifica a flag antes de chamar);
/// - Ataques de inimigos com "canDestroyObjectsOnAttack"
///   (EnemyPuzzleInteraction.ApplyAttackToObjects — chega aqui com projectile = null);
/// - ESCAVAR (Terra, P8): contacto contínuo de um animal com 'canTunnel'
///   (sem precisar de atacar) — ver HandleTunnelContact/digDuration.
/// </summary>
[RequireComponent(typeof(Collider2D))]
public class BreakableObject : MonoBehaviour, IProjectileDestructible
{
    [Header("Material")]
    public BreakableMaterial material = BreakableMaterial.Madeira;

    [Header("Resistência")]
    [Tooltip("Número de pancadas válidas até quebrar.")]
    [Min(1)] public int hitsToBreak = 1;

    [Header("Escavar (Terra — canTunnel, P8)")]
    [Tooltip("Só para material Terra: tempo de CONTACTO CONTÍNUO (segundos) com um animal 'canTunnel' até abrir o túnel. Não usa 'hitsToBreak' (esse continua a valer para uma pancada de ataque de quem tiver canTunnel).")]
    [Min(0.05f)] public float digDuration = 1f;

    [Header("Quem pode quebrar")]
    [Tooltip("Projécteis de inimigos (canDestroyObjects) quebram este objecto.")]
    public bool breakableByProjectiles = true;

    [Tooltip("Ataques de inimigos (canDestroyObjectsOnAttack) quebram este objecto.")]
    public bool breakableByEnemies = true;

    [Header("Ao Quebrar")]
    [Tooltip("Prefab instanciado ao quebrar (estilhaços/VFX).")]
    public GameObject breakVfxPrefab;

    public AudioClip breakSound;

    [Tooltip("Prefab opcional largado ao quebrar (ex: item).")]
    public GameObject dropPrefab;

    public UnityEvent onBroken;

    private int _hits;
    private bool _broken;
    private float _digProgress;

    /// <summary>Progresso de escavação (0-1), para VFX/UI (ex: poeira aumentando, barra de progresso).</summary>
    public float DigProgress01 => digDuration > 0f ? Mathf.Clamp01(_digProgress / digDuration) : 0f;

    /// <summary>
    /// Tenta quebrar com a forma do player (PlayerAttack/HeavyStrike):
    /// Madeira → canBreakWood; Gelo → canBreakIce; Terra → canTunnel (uma
    /// pancada também conta, além de escavar por contacto — ver HandleTunnelContact);
    /// Grande/Rachada → canBreakBig. Devolve true se a pancada contou (mesmo
    /// que ainda falte vida).
    /// </summary>
    public bool TryBreakByForm(AnimalFormData form)
    {
        if (_broken || form == null) return false;

        bool allowed;
        switch (material)
        {
            case BreakableMaterial.Madeira: allowed = form.canBreakWood; break;
            case BreakableMaterial.Gelo: allowed = form.canBreakIce; break;
            case BreakableMaterial.Terra: allowed = form.canTunnel; break;
            default: allowed = form.canBreakBig; break; // Grande/Rachada
        }

        if (!allowed) return false;

        RegisterHit();
        return true;
    }

    /// <summary>
    /// Escavar (Terra, P8): contacto contínuo de um animal com 'canTunnel'
    /// acumula progresso até 'digDuration', depois abre o túnel (Break).
    /// Chamado pelos colisores/triggers (ver OnCollisionStay2D/OnTriggerStay2D).
    /// Reseta o progresso se o animal sair ou não tiver canTunnel.
    /// </summary>
    private void HandleTunnelContact(Collider2D other)
    {
        if (_broken || material != BreakableMaterial.Terra) return;
        if (!other.CompareTag("Player")) return;

        var switcher = other.GetComponent<FormSwitcher>();
        var form = switcher != null ? switcher.CurrentForm : null;

        if (form == null || !form.canTunnel)
        {
            _digProgress = 0f;
            return;
        }

        _digProgress += Time.deltaTime;
        if (_digProgress >= digDuration) Break();
    }

    private void OnCollisionStay2D(Collision2D collision) => HandleTunnelContact(collision.collider);
    private void OnTriggerStay2D(Collider2D other) => HandleTunnelContact(other);

    private void ResetDigProgress(Collider2D other)
    {
        if (other.CompareTag("Player")) _digProgress = 0f;
    }

    private void OnCollisionExit2D(Collision2D collision) => ResetDigProgress(collision.collider);
    private void OnTriggerExit2D(Collider2D other) => ResetDigProgress(other);

    /// <summary>Quebra por projéctil de inimigo (IProjectileDestructible) ou por ataque de inimigo (projectile = null).</summary>
    public void DestroyByProjectile(ProjectileController projectile)
    {
        if (_broken) return;

        bool byEnemyMelee = projectile == null;
        if (byEnemyMelee && !breakableByEnemies) return;
        if (!byEnemyMelee && !breakableByProjectiles) return;

        RegisterHit();
    }

    private void RegisterHit()
    {
        _hits++;
        if (_hits < hitsToBreak) return;

        Break();
    }

    /// <summary>Quebra imediatamente (também chamável por eventos/puzzles).</summary>
    public void Break()
    {
        if (_broken) return;
        _broken = true;

        if (breakVfxPrefab != null)
            Instantiate(breakVfxPrefab, transform.position, Quaternion.identity);

        if (breakSound != null)
            AudioManager.Instance?.PlaySEAtPoint(breakSound, transform.position);

        if (dropPrefab != null)
            Instantiate(dropPrefab, transform.position, Quaternion.identity);

        onBroken?.Invoke();
        Destroy(gameObject);
    }
}
